{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Family income no more than 125% of the federal poverty level (FPL). Exact 2026 dollar amounts not specified in sources; contact local office to confirm based on current HHS poverty guidelines, which vary by household size (e.g., for 2025 reference: 1-person ~$19,000; 2-person ~$25,500 at 125% FPL—verify latest).[1][2][4]",
    "asset_limits": null,
    "other_requirements": ["Unemployed", "U.S. citizen or authorized to work", "Priority to: veterans/qualifying spouses, age 65+, limited English/low literacy, rural residents, disabled, low employment prospects, failed One-Stop employment services, homeless/at risk.[2]"]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time subsidized training positions (typically 20 hours/week) at nonprofits/public agencies; modest wages paid directly by ALTSD; on-the-job training, job development, resume building, post-placement support. Examples: customer service, maintenance, teacher assistant, childcare, food prep, retail, shipping/receiving. Goal: transition to unsubsidized employment.[4][5]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact NM Aging & Long-Term Services Department (ALTSD) via https://www.aging.nm.gov/aging-network/senior-employment-programs/ or local SCSEP office", "NICOA for eligible areas: https://www.nicoa.org/programs/scsep/ (covers NM)", "Goodwill NM: https://www.goodwillnm.org/seniors or call/walk-in to locations (e.g., 1030 18th Street NW)", "Find local provider via national locator or state workforce board.[1][2][4][5]"],
    "processing_time": "Not specified; enrollment if eligible and no waitlist.",
    "waitlist": "Possible depending on location and funding; varies by local availability and funding cycles (some 2025 pauses noted).[1]",
    "forms": ["Complete application at local SCSEP office; no specific form name/number listed."],
    "documents": ["Proof of age, income, unemployment status, work authorization; physical exam offered at enrollment (not required to apply).[1][2][7]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Administered by multiple grantees (e.g., NICOA for parts of NM including American Indian focus, Goodwill, ALTSD); availability, wait times, positions vary by funding/local offices; 26 of 33 counties 'frontier' with rural priority.[2][3][4][5]",
    "offices_or_providers": ["NM Aging & Long-Term Services Department (ALTSD)", "NICOA (AZ, MN, NM, ND, OK, SD, WI)", "Goodwill Industries of NM", "Local SCSEP offices via state workforce boards.[2][3][4][5]"]
  },
  "official_source": "https://www.aging.nm.gov/aging-network/senior-employment-programs/",
  "gotchas": ["Funding fluctuations may cause pauses/slowdowns (e.g., 2025 issues); local waitlists common; not guaranteed permanent job—focus is training to unsubsidized employment; priority groups get preference; separate from state-funded SEP (similar but general funds); physical exam post-enrollment.[1][2][4][7]", "Income test strictly 125% FPL—contact for exact table; open to all qualifying, not just Native American via NICOA.[2]"],
  "data_shape_notes": "Grantee-based with multiple providers (NICOA, Goodwill, ALTSD); priority tiers affect access; funding variability by region; no fixed asset limits or statewide wait times; rural/frontier county focus in NM.[2][3][4]"
}
